=RESUME ANALYSIS REQUEST

Candidate Resume Text:
{{ $json.text }}

Applied Job Title:
{{ $('Candidate_Application_Trigger').item.json["Applying For"] }}

Job Description:
{{ $('Data_Sanitization_Engine').item.json["Job Description"] }}

PERFORM COMPREHENSIVE RESUME EVALUATION AND RETURN STRUCTURED JSON RESPONSE ONLY.

parameters.jsCode:
// هنحوّل أي object جاي من الفورم
// إلى object جديد بمفاتيح عامة Question1, Question2...
return items.map(item => {
  const input = item.json;
  const output = {};
  let i = 1;

  for (const key in input) {
    if (Object.prototype.hasOwnProperty.call(input, key)) {
      // نتجاهل الحقول الخاصة بالنظام زي submittedAt و formMode
      if (["submittedAt", "formMode"].includes(key)) continue;

      output[`Question${i}`] = input[key];
      i++;
    }
  }

  return { json: output };
});

// N8N JavaScript Node Code for Formal CV Analysis Report (Maximum 2 Pages)
// Ultra-formal, concise version with executive focus

// Input data structure from previous nodes
const inputData = $input.all();
const reportData = inputData[0].json.output || inputData[0].json;

// Extract essential information only
const basicInfo = {
  applicantName: reportData.basic_information?.applicant_name || "Unknown Candidate",
  positionApplied: reportData.basic_information?.position_applied || "Not Specified",
  yearsExperience: reportData.basic_information?.years_experience || 0,
  education: reportData.basic_information?.education || "Not Provided"
};

// Extract core analysis data
const analysisResults = reportData.analysis_results || [];
const overallAssessment = reportData.overall_assessment || {};
const strengths = (reportData.strengths || []).slice(0, 4); // Top 4 only
const improvements = (reportData.areas_for_improvement || []).slice(0, 4); // Top 4 only
const recommendations = reportData.recommendations || {};

// Analysis metrics
const totalScore = overallAssessment.total_score?.obtained || 0;
const maxScore = overallAssessment.total_score?.max || 50;
const percentage = overallAssessment.total_score?.percent || 0;
const classification = overallAssessment.classification || "Candidate";
const jobMatch = Math.round((overallAssessment.job_match || 0) * 100);
const analysisDate = reportData.analysis_date || new Date().toLocaleDateString('en-US');

// Utility functions
function getScoreClass(score, maxPossible = 10) {
  const percentage = (score / maxPossible) * 100;
  if (percentage >= 80) return "excellent";
  if (percentage >= 65) return "good"; 
  if (percentage >= 50) return "average";
  return "poor";
}

function getPriorityColor(priority) {
  if (priority === "High") return "#dc3545";
  if (priority === "Medium") return "#ffc107";
  return "#28a745";
}

// Generate ultra-formal, concise HTML report (2 pages max)
const htmlReport = `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>CV Assessment Report - ${basicInfo.applicantName}</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Times New Roman', Times, serif;
            font-size: 12px;
            line-height: 1.4;
            color: #000;
            max-width: 210mm;
            margin: 0 auto;
            padding: 15mm;
            background: white;
        }

        .letterhead {
            text-align: center;
            border-bottom: 2px solid #000;
            padding-bottom: 10px;
            margin-bottom: 20px;
        }

        .letterhead h1 {
            font-size: 18px;
            font-weight: bold;
            text-transform: uppercase;
            letter-spacing: 2px;
            margin-bottom: 5px;
        }

        .letterhead .subtitle {
            font-size: 11px;
            color: #666;
            text-transform: uppercase;
        }

        .header-info {
            display: flex;
            justify-content: space-between;
            margin-bottom: 15px;
            font-size: 10px;
            color: #666;
        }

        .section {
            margin-bottom: 15px;
            page-break-inside: avoid;
        }

        .section-title {
            font-size: 14px;
            font-weight: bold;
            text-transform: uppercase;
            border-bottom: 1px solid #000;
            padding-bottom: 2px;
            margin-bottom: 8px;
            letter-spacing: 1px;
        }

        .candidate-grid {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 15px;
            margin-bottom: 15px;
        }

        .info-box {
            border: 1px solid #ccc;
            padding: 8px;
            background: #f9f9f9;
        }

        .info-label {
            font-weight: bold;
            font-size: 10px;
            color: #666;
            text-transform: uppercase;
        }

        .info-value {
            font-size: 12px;
            margin-top: 2px;
        }

        .assessment-table {
            width: 100%;
            border-collapse: collapse;
            font-size: 11px;
            margin-bottom: 12px;
        }

        .assessment-table th {
            background: #f0f0f0;
            padding: 6px;
            text-align: left;
            font-weight: bold;
            border: 1px solid #999;
            font-size: 10px;
            text-transform: uppercase;
        }

        .assessment-table td {
            padding: 5px 6px;
            border: 1px solid #ccc;
            vertical-align: top;
        }

        .score-badge {
            display: inline-block;
            padding: 2px 6px;
            font-weight: bold;
            font-size: 10px;
            text-align: center;
            min-width: 35px;
        }

        .score-badge.excellent { 
            background: #d4edda; 
            color: #155724; 
            border: 1px solid #c3e6cb; 
        }
        .score-badge.good { 
            background: #d1ecf1; 
            color: #0c5460; 
            border: 1px solid #bee5eb; 
        }
        .score-badge.average { 
            background: #fff3cd; 
            color: #856404; 
            border: 1px solid #ffeaa7; 
        }
        .score-badge.poor { 
            background: #f8d7da; 
            color: #721c24; 
            border: 1px solid #f5c6cb; 
        }

        .summary-box {
            border: 2px solid #000;
            padding: 12px;
            text-align: center;
            background: #f8f8f8;
            margin: 15px 0;
        }

        .final-score {
            font-size: 24px;
            font-weight: bold;
            margin-bottom: 5px;
        }

        .classification {
            font-size: 14px;
            font-weight: bold;
            text-transform: uppercase;
            color: #333;
        }

        .two-column {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 20px;
            margin: 10px 0;
        }

        .strength-item, .improvement-item {
            font-size: 11px;
            padding: 4px 0;
            border-bottom: 1px dotted #ccc;
        }

        .recommendation-box {
            border: 2px solid ${getPriorityColor(recommendations.interview_priority)};
            padding: 10px;
            background: #f9f9f9;
            margin-top: 15px;
        }

        .recommendation-title {
            font-weight: bold;
            font-size: 13px;
            text-transform: uppercase;
            margin-bottom: 5px;
            color: ${getPriorityColor(recommendations.interview_priority)};
        }

        .focus-areas {
            font-size: 10px;
            margin-top: 5px;
        }

        .footer {
            position: fixed;
            bottom: 10mm;
            left: 15mm;
            right: 15mm;
            text-align: center;
            font-size: 9px;
            color: #666;
            border-top: 1px solid #ccc;
            padding-top: 5px;
        }

        @media print {
            body {
                margin: 0;
                padding: 15mm;
            }
            .footer {
                position: fixed;
            }
        }

        @page {
            size: A4;
            margin: 15mm;
        }
    </style>
</head>
<body>
    <!-- Letterhead -->
    <div class="letterhead">
        <h1>Curriculum Vitae Assessment Report</h1>
        <div class="subtitle">Confidential Human Resources Document</div>
    </div>

    <!-- Header Information -->
    <div class="header-info">
        <div>Assessment Date: ${analysisDate}</div>
        <div>Generated: ${new Date().toLocaleString('en-US')}</div>
        <div>Page 1 of 2</div>
    </div>

    <!-- Candidate Information -->
    <div class="section">
        <div class="section-title">I. Candidate Profile</div>
        <div class="candidate-grid">
            <div class="info-box">
                <div class="info-label">Full Name</div>
                <div class="info-value">${basicInfo.applicantName}</div>
            </div>
            <div class="info-box">
                <div class="info-label">Position Applied</div>
                <div class="info-value">${basicInfo.positionApplied}</div>
            </div>
            <div class="info-box">
                <div class="info-label">Experience</div>
                <div class="info-value">${basicInfo.yearsExperience} Years</div>
            </div>
            <div class="info-box">
                <div class="info-label">Education</div>
                <div class="info-value">${basicInfo.education}</div>
            </div>
        </div>
    </div>

    <!-- Assessment Results -->
    <div class="section">
        <div class="section-title">II. Assessment Matrix</div>
        <table class="assessment-table">
            <thead>
                <tr>
                    <th style="width: 40%;">Evaluation Criteria</th>
                    <th style="width: 15%;">Score</th>
                    <th style="width: 45%;">Assessment Notes</th>
                </tr>
            </thead>
            <tbody>
                ${analysisResults.slice(0, 6).map(result => `
                    <tr>
                        <td><strong>${result.criteria}</strong></td>
                        <td><span class="score-badge ${getScoreClass(result.score)}">${result.score}/10</span></td>
                        <td>${result.notes.substring(0, 80)}${result.notes.length > 80 ? '...' : ''}</td>
                    </tr>
                `).join('')}
            </tbody>
        </table>
    </div>

    <!-- Overall Assessment -->
    <div class="section">
        <div class="section-title">III. Executive Summary</div>
        <div class="summary-box">
            <div class="final-score">${totalScore}/${maxScore} Points (${percentage}%)</div>
            <div class="classification">${classification} • Job Match: ${jobMatch}%</div>
        </div>

        <div class="two-column">
            <div>
                <div class="section-title" style="font-size: 12px; margin-bottom: 8px;">Key Strengths</div>
                ${strengths.map((strength, index) => `
                    <div class="strength-item">${index + 1}. ${strength}</div>
                `).join('')}
            </div>
            <div>
                <div class="section-title" style="font-size: 12px; margin-bottom: 8px;">Development Areas</div>
                ${improvements.map((improvement, index) => `
                    <div class="improvement-item">${index + 1}. ${improvement}</div>
                `).join('')}
            </div>
        </div>
    </div>

    <!-- Final Recommendation -->
    <div class="section">
        <div class="section-title">IV. Final Recommendation</div>
        <div class="recommendation-box">
            <div class="recommendation-title">
                Decision: ${recommendations.final_recommendation || 'Pending Review'} 
                (Priority: ${recommendations.interview_priority || 'Standard'})
            </div>

            ${recommendations.interview_focus_areas && recommendations.interview_focus_areas.length > 0 ? `
                <div class="focus-areas">
                    <strong>Interview Focus Areas:</strong> 
                    ${recommendations.interview_focus_areas.slice(0, 3).join(', ')}
                </div>
            ` : ''}
        </div>
    </div>

    <!-- Footer -->
    <div class="footer">
        This document contains confidential information. Unauthorized distribution is prohibited.<br>
        HR Department • Automated CV Assessment System v2.0
    </div>
</body>
</html>
`;

// Return streamlined output
return [{
    json: {
        // Essential candidate data
        candidate_name: basicInfo.applicantName,
        position_applied: basicInfo.positionApplied,
        total_score: `${totalScore}/${maxScore}`,
        percentage_score: percentage,
        classification: classification,
        job_match: `${jobMatch}%`,

        // Key recommendations
        final_recommendation: recommendations.final_recommendation,
        interview_priority: recommendations.interview_priority,

        // Core strengths and improvements (limited)
        key_strengths: strengths,
        development_areas: improvements,

        // Report metadata
        report_type: "Formal CV Assessment (2-Page)",
        analysis_date: analysisDate,
        page_limit: "Maximum 2 Pages",

        // Generated formal HTML report
        html_report: htmlReport,

        // Executive summary for workflows
        executive_summary: {
            candidate: basicInfo.applicantName,
            position: basicInfo.positionApplied,
            score: `${percentage}%`,
            recommendation: recommendations.final_recommendation,
            priority: recommendations.interview_priority,
            status: classification
        }
    }
}];
